import React, { useState } from 'react';

const SolicitarOferta = () => {
  const [formData, setFormData] = useState({
    tipo_solicitud: '',
    descripcion: '',
    justificacion: '',
    archivos: null
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value
    });
  };

  const handleFileChange = (e) => {
    setFormData({
      ...formData,
      archivos: e.target.files
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log('Solicitud:', formData);
    alert('Solicitud enviada (simulación)');
  };

  return (
    <div style={styles.formContainer}>
      <h2 style={styles.formTitle}>📝 Solicitar Oferta</h2>
      <form onSubmit={handleSubmit} style={styles.form}>
        
        <div style={styles.formGroup}>
          <label style={styles.label}>Tipo de Solicitud:</label>
          <select 
            name="tipo_solicitud"
            value={formData.tipo_solicitud}
            onChange={handleChange}
            style={styles.select}
            required
          >
            <option value="">Seleccione...</option>
            <option value="nueva">Nueva oferta</option>
            <option value="modificacion">Modificación de oferta</option>
            <option value="cancelacion">Cancelación</option>
          </select>
        </div>

        <div style={styles.formGroup}>
          <label style={styles.label}>Descripción de la solicitud:</label>
          <textarea 
            name="descripcion"
            value={formData.descripcion}
            onChange={handleChange}
            style={styles.textarea} 
            rows="5" 
            placeholder="Describa detalladamente su solicitud..."
            required
          />
        </div>

        <div style={styles.formGroup}>
          <label style={styles.label}>Justificación:</label>
          <textarea 
            name="justificacion"
            value={formData.justificacion}
            onChange={handleChange}
            style={styles.textarea} 
            rows="3" 
            placeholder="Justifique su solicitud..."
            required
          />
        </div>

        <div style={styles.formGroup}>
          <label style={styles.label}>Documentos adjuntos:</label>
          <input 
            type="file" 
            name="archivos"
            onChange={handleFileChange}
            style={styles.fileInput} 
            multiple 
          />
          <small style={styles.fileHint}>Puede seleccionar múltiples archivos</small>
        </div>

        <button type="submit" style={styles.submitButton}>
          Enviar Solicitud
        </button>
      </form>
    </div>
  );
};

const styles = {
  formContainer: {
    maxWidth: '800px',
    margin: '0 auto'
  },
  formTitle: {
    color: '#2c3e50',
    borderBottom: '2px solid #3498db',
    paddingBottom: '10px',
    marginBottom: '25px',
    fontSize: '24px'
  },
  form: {
    display: 'flex',
    flexDirection: 'column',
    gap: '20px'
  },
  formGroup: {
    display: 'flex',
    flexDirection: 'column',
    gap: '5px'
  },
  label: {
    fontSize: '14px',
    fontWeight: 'bold',
    color: '#34495e'
  },
  select: {
    padding: '10px',
    border: '1px solid #ddd',
    borderRadius: '4px',
    fontSize: '14px',
    backgroundColor: 'white',
    cursor: 'pointer'
  },
  textarea: {
    padding: '10px',
    border: '1px solid #ddd',
    borderRadius: '4px',
    fontSize: '14px',
    resize: 'vertical',
    fontFamily: 'Arial, sans-serif'
  },
  fileInput: {
    padding: '10px',
    border: '1px solid #ddd',
    borderRadius: '4px',
    fontSize: '14px',
    backgroundColor: 'white',
    cursor: 'pointer'
  },
  fileHint: {
    fontSize: '12px',
    color: '#7f8c8d',
    marginTop: '5px'
  },
  submitButton: {
    backgroundColor: '#3498db',
    color: 'white',
    padding: '15px',
    border: 'none',
    borderRadius: '4px',
    fontSize: '16px',
    fontWeight: 'bold',
    cursor: 'pointer',
    marginTop: '20px',
    transition: 'background-color 0.3s'
  }
};

export default SolicitarOferta;
